        IDLE,
        PROCESSING
    } state_t;

    // State register
    state_t state, next_state;

    // Output register
    reg z;

    // Output register for the current bit
    reg current_bit;

    // Shift register to hold the input bits
    reg [31:0] input_bits;

    // Counter to track the number of input bits
    reg [5:0] bit_count;

    // Output register for the result
    reg [31:0] result;

    // State machine logic
    always @(posedge clk) begin
        if (areset) begin
            state <= IDLE;
            z <= 1'b0;
            current_bit <= 1'b0;
            input_bits <= 32'b0;
            bit_count <= 6'd0;
            result <= 32'b0;
