                    if (x) begin
                        state <= PROCESSING;
                        current_bit <= x;
                        input_bits[0] <= x;
                        bit_count <= 6'd1;
                        result <= 32'b0;
                    end
                end
                PROCESSING: begin
                    if (bit_count < 6'd32) begin
                        // Shift the input bits to the left
                        input_bits <= {input_bits[30:0], current_bit};
                        // Compute the result bit
                        result[bit_count] <= current_bit;
                        // Increment the bit counter
                        bit_count <= bit_count + 6'd1;
                        // Compute the next current bit
                        current_bit <= x;
                    end else begin
                        // All input bits have been processed
                        state <= IDLE;
                        // Compute the 2's complement of the input
                        result <= ~input_bits + 1'b1;
                        z <= result[31];
                    end
                end
            endcase
        end
    end

