  input  clk,
  input  a,
  input  b,
  output q,
  output state
);

  reg state;
  wire next_state;
  wire next_q;

  // Combinational logic to compute next state and next q
  assign next_state = (a & b) | (state & ~a);
  assign next_q = (a & b) | (state & ~a) | (state & b);

  // Sequential logic to update state and q on the rising edge of the clock
  always @(posedge clk) begin
    state <= next_state;
    q <= next_q;
